 12→use anyhow::{Context, Result};
 13→use libsql::{Builder, Connection, Database};
 14→
 15→/// Async database handle wrapping a libsql Database.
 16→///
 17→/// Supports two modes:
 18→/// - **Turso embedded replica** when TURSO_DATABASE_URL and TURSO_AUTH_TOKEN are set
 19→/// - **Local SQLite** otherwise (dev/offline fallback)
 20→#[derive(Clone)]
 21→pub struct DbHandle {
 22→    db: Arc<Database>,
 23→    /// Shared connection used for all operations.
 24→    /// libsql's `:memory:` databases create a new database per `connect()` call,
 25→    /// so we keep one connection alive and reuse it everywhere.
 26→    ///
 27→    /// Safety: libsql connections are internally synchronized (serialized via mutex),
 28→    /// so sharing a single `Connection` behind `Arc` is safe for concurrent use
 29→    /// across multiple tokio tasks.
 30→    conn: Arc<Connection>,
 31→}
 32→
 33→impl DbHandle {
 34→    /// Open a local-only SQLite database at the given path.
 35→    pub async fn new_local(path: &Path) -> Result<Self> {
 36→        let path_str = path.to_string_lossy().to_string();
 37→        let db = Builder::new_local(&path_str)
 38→            .build()
 39→            .await
 40→            .context("Failed to open local SQLite database")?;
 41→        Self::from_db(db).await
 42→    }
 43→
 44→    /// Open a Turso embedded replica with local file cache.
 45→    pub async fn new_remote_replica(
 46→        local_path: &Path,
 47→        url: &str,
 48→        token: &str,
 49→    ) -> Result<Self> {
 50→        let path_str = local_path.to_string_lossy().to_string();
 51→        let db = Builder::new_remote_replica(
 52→            &path_str,
 53→            url.to_string(),
 54→            token.to_string(),
 55→        )
 56→        .sync_interval(Duration::from_secs(60))
 57→        .read_your_writes(true)
 58→        .build()
 59→        .await
 60→        .context("Failed to open Turso embedded replica")?;
 61→        Self::from_db(db).await
 62→    }
 63→
 64→    /// Open an in-memory database (for testing).
 65→    pub async fn new_in_memory() -> Result<Self> {
 66→        let db = Builder::new_local(":memory:")
 67→            .build()
 68→            .await
 69→            .context("Failed to open in-memory database")?;
 70→        Self::from_db(db).await
 71→    }
 72→
 73→    async fn from_db(db: Database) -> Result<Self> {
 74→        let conn = db.connect().context("Failed to get initial connection")?;
 75→        init_pragmas(&conn).await?;
 76→        migrations::run_migrations(&conn).await?;
 77→        Ok(Self {
 78→            db: Arc::new(db),
 79→            conn: Arc::new(conn),
 80→        })
 81→    }
 82→
 83→    /// Get a reference to the shared connection.
 84→    pub fn conn(&self) -> &Connection {
 85→        &self.conn
 86→    }
 87→
 88→    /// Sync embedded replica with remote (no-op for local-only).
 89→    pub async fn sync(&self) -> Result<()> {
 90→        self.db
 91→            .sync()
 92→            .await
 93→            .map_err(|e| anyhow::anyhow!(e))
 94→            .context("Failed to sync embedded replica with Turso remote")?;
 95→        Ok(())
 96→    }
 97→
 98→    // ── Project convenience methods ──────────────────────────────────
 99→
100→    pub async fn list_projects(&self) -> Result<Vec<super::models::Project>> {
101→        let conn = self.conn();
102→        projects::list_projects(&conn).await
103→    }
104→
105→    pub async fn create_project(&self, name: &str, path: &str) -> Result<super::models::Project> {
106→        let conn = self.conn();
107→        projects::create_project(&conn, name, path).await
108→    }
109→
110→    pub async fn get_project(&self, id: i64) -> Result<Option<super::models::Project>> {
111→        let conn = self.conn();
112→        projects::get_project(&conn, id).await
113→    }
114→
115→    pub async fn update_project_github_repo(
116→        &self,
117→        id: i64,
118→        github_repo: &str,
119→    ) -> Result<super::models::Project> {
120→        let conn = self.conn();
121→        projects::update_project_github_repo(&conn, id, github_repo).await
122→    }
123→
124→    pub async fn delete_project(&self, id: i64) -> Result<bool> {
125→        let conn = self.conn();
126→        projects::delete_project(&conn, id).await
127→    }
128→
