132→        &self,
133→        project_id: i64,
134→        title: &str,
135→        description: &str,
136→        column: &super::models::IssueColumn,
137→    ) -> Result<super::models::Issue> {
138→        let conn = self.conn();
139→        issues::create_issue(&conn, project_id, title, description, column).await
