428→        .await
429→        .context("Failed to set WAL mode")?;
430→    conn.query("PRAGMA busy_timeout=5000", ())
431→        .await
432→        .context("Failed to set busy_timeout")?;
433→    conn.execute("PRAGMA foreign_keys=ON", ())
434→        .await
435→        .context("Failed to enable foreign keys")?;
436→    Ok(())
437→}
