448→        let project = db.create_project("visibility-test", "/tmp/visibility-test")
449→            .await
450→            .unwrap();
451→        assert!(project.id > 0);
452→
453→        // Read the project back through the same db handle
454→        let fetched = db.get_project(project.id)
455→            .await
456→            .unwrap()
457→            .expect("project should be visible through the shared connection");
458→        assert_eq!(fetched.name, "visibility-test");
459→        assert_eq!(fetched.path, "/tmp/visibility-test");
460→
461→        // Also verify list_projects sees it
462→        let all = db.list_projects().await.unwrap();
463→        assert_eq!(all.len(), 1);
