468→/// Run integrity check on startup. Logs warning but does not fail.
469→pub async fn health_check(conn: &Connection) {
470→    match conn.query("PRAGMA integrity_check", ()).await {
471→        Ok(mut rows) => {
472→            match rows.next().await {
473→                Ok(Some(row)) => {
474→                    match row.get::<String>(0) {
475→                        Ok(result) if result == "ok" => { /* healthy */ }
476→                        Ok(result) => {
477→                            eprintln!("[db] WARNING: database integrity check failed: {result}");
478→                        }
479→                        Err(e) => {
480→                            eprintln!("[db] WARNING: could not read integrity check result: {e}");
481→                        }
482→                    }
483→                }
484→                Ok(None) => {
485→                    eprintln!("[db] WARNING: integrity check returned no rows");
486→                }
487→                Err(e) => {
488→                    eprintln!("[db] WARNING: failed to read integrity check row: {e}");
489→                }
490→            }
491→        }
492→        Err(e) => {
493→            eprintln!("[db] WARNING: failed to run integrity check: {e}");
494→        }
495→    }
496→}
