/// Sync embedded replica with remote. No-op for local-only databases.
pub async fn sync(&self) -> Result<()> {
    if self.is_remote {
        self.db
            .sync()
            .await
            .map_err(|e| anyhow::anyhow!(e))
            .context("Failed to sync embedded replica with Turso remote")?;
    }
    Ok(())
