/// Set WAL mode, busy timeout, and enable foreign keys.
/// Turso embedded replicas manage these internally, so pragmas are only set for local databases.
async fn init_pragmas(conn: &Connection, is_remote: bool) -> Result<()> {
    if is_remote {
        // Turso handles WAL mode, busy timeout, and foreign keys internally.
        return Ok(());
    }
    // journal_mode and busy_timeout return rows, so use query() instead of execute()
    conn.query("PRAGMA journal_mode=WAL", ())
        .await
        .context("Failed to set WAL mode")?;
    conn.query("PRAGMA busy_timeout=5000", ())
        .await
        .context("Failed to set busy_timeout")?;
    conn.execute("PRAGMA foreign_keys=ON", ())
        .await
        .context("Failed to enable foreign keys")?;
    Ok(())
}

