use std::path::Path;
use std::sync::Arc;
use std::time::Duration;

use anyhow::{Context, Result};
use libsql::{Builder, Connection, Database};

/// Async database handle wrapping a libsql Database.
///
/// Supports two modes:
/// - **Turso embedded replica** when TURSO_DATABASE_URL and TURSO_AUTH_TOKEN are set
/// - **Local SQLite** otherwise (dev/offline fallback)
#[derive(Clone)]
pub struct DbHandle {
    db: Arc<Database>,
    /// Shared connection used for all operations.
    /// libsql's `:memory:` databases create a new database per `connect()` call,
    /// so we keep one connection alive and reuse it everywhere.
    ///
    /// Safety: libsql connections are internally synchronized (serialized via mutex),
    /// so sharing a single `Connection` behind `Arc` is safe for concurrent use
    /// across multiple tokio tasks.
    conn: Arc<Connection>,
    /// Whether this handle is connected to a Turso remote replica.
    is_remote: bool,
}

impl DbHandle {
    /// Open a local-only SQLite database at the given path.
    pub async fn new_local(path: &Path) -> Result<Self> {
        let path_str = path.to_string_lossy().to_string();
        let db = Builder::new_local(&path_str)
            .build()
            .await
            .context("Failed to open local SQLite database")?;
        Self::from_db(db, false).await
    }

    /// Open a Turso embedded replica with local file cache.
    pub async fn new_remote_replica(
        local_path: &Path,
        url: &str,
        token: &str,
    ) -> Result<Self> {
        let path_str = local_path.to_string_lossy().to_string();
        let db = Builder::new_remote_replica(
            &path_str,
            url.to_string(),
            token.to_string(),
        )
        .sync_interval(Duration::from_secs(60))
        .read_your_writes(true)
        .build()
        .await
        .context("Failed to open Turso embedded replica")?;
        Self::from_db(db, true).await
    }

    /// Open an in-memory database (for testing).
    pub async fn new_in_memory() -> Result<Self> {
        let db = Builder::new_local(":memory:")
            .build()
            .await
            .context("Failed to open in-memory database")?;
        Self::from_db(db, false).await
    }

    async fn from_db(db: Database, is_remote: bool) -> Result<Self> {
        // For remote replicas, sync first to pull down the remote schema
        // before running local migrations or pragmas.
        if is_remote {
            db.sync()
                .await
                .map_err(|e| anyhow::anyhow!(e))
                .context("Failed initial sync of embedded replica")?;
        }
        let conn = db.connect().context("Failed to get initial connection")?;
        init_pragmas(&conn, is_remote).await?;
        migrations::run_migrations(&conn).await?;
        Ok(Self {
            db: Arc::new(db),
            conn: Arc::new(conn),
            is_remote,
        })
    }

    /// Get a reference to the shared connection.
    pub fn conn(&self) -> &Connection {
        &self.conn
    }

    /// Sync embedded replica with remote. No-op for local-only databases.
    pub async fn sync(&self) -> Result<()> {
        if self.is_remote {
            self.db
                .sync()
                .await
                .map_err(|e| anyhow::anyhow!(e))
                .context("Failed to sync embedded replica with Turso remote")?;
        }
        Ok(())
    }

